class AnalyticsSystem{constructor(options={}){this.options={endpoint:options.endpoint||'/api/analytics',trackWebVitals:true,trackUserBehavior:true,trackPerformance:true,debugMode:options.debugMode||false,sampleRate:options.sampleRate||0.1,...options};this.sessionId=this.generateSessionId();this.pageStartTime=Date.now();this.events=[];this.init();}init(){this.trackPageView();if(this.options.trackWebVitals){this.trackCoreWebVitals();}if(this.options.trackUserBehavior){this.trackUserInteractions();}if(this.options.trackPerformance){this.trackPerformanceMetrics();}setInterval(()=>this.sendEvents(),30000);window.addEventListener('beforeunload',()=>this.sendEvents());}generateSessionId(){return 'session_'+Date.now()+'_'+Math.random().toString(36).substr(2,9);}shouldSample(){return Math.random()<this.options.sampleRate;}trackPageView(){const pageData={type:'pageview',url:window.location.href,title:document.title,referrer:document.referrer,userAgent:navigator.userAgent,timestamp:Date.now(),sessionId:this.sessionId,viewport:{width:window.innerWidth,height:window.innerHeight},device:this.getDeviceInfo()};this.addEvent(pageData);}trackCoreWebVitals(){this.observeLCP();this.observeFID();this.observeCLS();}observeLCP(){if(!window.PerformanceObserver)return;const observer=new PerformanceObserver((list)=>{const entries=list.getEntries();const lastEntry=entries[entries.length-1];this.addEvent({type:'webvital_lcp',value:lastEntry.startTime,url:lastEntry.url,timestamp:Date.now(),sessionId:this.sessionId});});observer.observe({entryTypes:['largest-contentful-paint']});}observeFID(){if(!window.PerformanceObserver)return;const observer=new PerformanceObserver((list)=>{list.getEntries().forEach(entry=>{this.addEvent({type:'webvital_fid',value:entry.processingStart-entry.startTime,inputType:entry.name,timestamp:Date.now(),sessionId:this.sessionId});});});observer.observe({entryTypes:['first-input']});}observeCLS(){if(!window.PerformanceObserver)return;let clsValue=0;const observer=new PerformanceObserver((list)=>{list.getEntries().forEach(entry=>{if(!entry.hadRecentInput){clsValue+=entry.value;}});this.addEvent({type:'webvital_cls',value:clsValue,timestamp:Date.now(),sessionId:this.sessionId});});observer.observe({entryTypes:['layout-shift']});}trackUserInteractions(){document.addEventListener('click',(e)=>{if(this.shouldSample()){this.addEvent({type:'click',target:this.getElementSelector(e.target),coordinates:{x:e.clientX,y:e.clientY},timestamp:Date.now(),sessionId:this.sessionId});}});let scrollTimeout;document.addEventListener('scroll',()=>{clearTimeout(scrollTimeout);scrollTimeout=setTimeout(()=>{if(this.shouldSample()){this.addEvent({type:'scroll',depth:this.getScrollDepth(),timestamp:Date.now(),sessionId:this.sessionId});}},1000);});document.addEventListener('submit',(e)=>{const form=e.target;if(form.tagName==='FORM'){this.addEvent({type:'form_submit',form:this.getFormIdentifier(form),timestamp:Date.now(),sessionId:this.sessionId});}});}trackPerformanceMetrics(){window.addEventListener('load',()=>{setTimeout(()=>{const navigation=performance.getEntriesByType('navigation')[0];this.addEvent({type:'performance',metrics:{dns:navigation.domainLookupEnd-navigation.domainLookupStart,tcp:navigation.connectEnd-navigation.connectStart,ssl:navigation.secureConnectionStart>0 ? navigation.connectEnd-navigation.secureConnectionStart:0,ttfb:navigation.responseStart-navigation.requestStart,download:navigation.responseEnd-navigation.responseStart,domParse:navigation.domContentLoadedEventStart-navigation.responseEnd,domReady:navigation.domContentLoadedEventEnd-navigation.domContentLoadedEventStart,loadComplete:navigation.loadEventEnd-navigation.loadEventStart,total:navigation.loadEventEnd-navigation.navigationStart},timestamp:Date.now(),sessionId:this.sessionId});},0);});this.trackResourceTiming();}trackResourceTiming(){if(!window.PerformanceObserver)return;const observer=new PerformanceObserver((list)=>{list.getEntries().forEach(entry=>{if(entry.entryType==='resource'){this.addEvent({type:'resource',name:entry.name,type:this.getResourceType(entry.name),size:entry.transferSize,duration:entry.duration,cached:entry.transferSize===0&&entry.decodedBodySize>0,timestamp:Date.now(),sessionId:this.sessionId});}});});observer.observe({entryTypes:['resource']});}getDeviceInfo(){return{type:this.getDeviceType(),os:this.getOperatingSystem(),browser:this.getBrowser(),language:navigator.language,cookieEnabled:navigator.cookieEnabled,doNotTrack:navigator.doNotTrack};}getDeviceType(){const width=window.innerWidth;if(width<768)return 'mobile';if(width<1024)return 'tablet';return 'desktop';}getOperatingSystem(){const userAgent=navigator.userAgent.toLowerCase();if(userAgent.includes('windows'))return 'Windows';if(userAgent.includes('mac'))return 'macOS';if(userAgent.includes('linux'))return 'Linux';if(userAgent.includes('android'))return 'Android';if(userAgent.includes('ios')||userAgent.includes('iphone')||userAgent.includes('ipad'))return 'iOS';return 'Unknown';}getBrowser(){const userAgent=navigator.userAgent;if(userAgent.includes('Chrome'))return 'Chrome';if(userAgent.includes('Firefox'))return 'Firefox';if(userAgent.includes('Safari'))return 'Safari';if(userAgent.includes('Edge'))return 'Edge';return 'Unknown';}getElementSelector(element){if(element.id)return `#${element.id}`;if(element.className)return `.${element.className.split(' ').join('.')}`;return element.tagName.toLowerCase();}getScrollDepth(){const scrollTop=window.pageYOffset||document.documentElement.scrollTop;const documentHeight=document.documentElement.scrollHeight-window.innerHeight;return Math.round((scrollTop/documentHeight)*100);}getFormIdentifier(form){if(form.id)return `#${form.id}`;if(form.className)return `form.${form.className.split(' ')[0]}`;if(form.action)return `form[${form.action}]`;return 'form';}getResourceType(url){const extension=url.split('.').pop()?.toLowerCase();const imageExtensions=['jpg','jpeg','png','gif','svg','webp'];const scriptExtensions=['js','mjs'];const styleExtensions=['css','scss','sass'];if(imageExtensions.includes(extension))return 'image';if(scriptExtensions.includes(extension))return 'script';if(styleExtensions.includes(extension))return 'stylesheet';if(extension==='font'||extension==='woff'||extension==='woff2'||extension==='ttf')return 'font';return 'other';}addEvent(event){this.events.push(event);if(this.options.debugMode){console.log('Analytics Event:',event);}}async sendEvents(){if(this.events.length===0)return;const eventsToSend=[...this.events];this.events=[];try{await fetch(this.options.endpoint,{method:'POST',headers:{'Content-Type':'application/json',},body:JSON.stringify({events:eventsToSend,session:this.sessionId,timestamp:Date.now()})});if(this.options.debugMode){console.log(`Sent ${eventsToSend.length}analytics events`);}}catch(error){this.events=[...eventsToSend,...this.events];if(this.options.debugMode){console.warn('Failed to send analytics events:',error);}}}}document.addEventListener('DOMContentLoaded',()=>{if(window.location.hostname==='localhost'&&!window.analyticsDebug){return;}window.analyticsSystem=new AnalyticsSystem({endpoint:'/api/analytics',trackWebVitals:true,trackUserBehavior:true,trackPerformance:true,debugMode:window.analyticsDebug||false,sampleRate:0.1});});if(typeof module!=='undefined'&&module.exports){module.exports=AnalyticsSystem;}